#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int countSubarrays(vector<int>& nums, int k) {
        int count = 0;
        unordered_map<int, int> xor_count = {{0, 1}};
        int curr_xor = 0;
        for (int num : nums) {
            curr_xor ^= num;
            count += xor_count[curr_xor ^ k];
            xor_count[curr_xor]++;
        }
        return count;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    int k;
    if (!(cin >> k)) return 0;
    Solution sol;
    int ans = sol.countSubarrays(nums, k);
    cout << ans << "\n";
    return 0;
}
